// ============================================================
// NORMALIZE INPUT — Multi-channel, multi-media
// Handles: text, audio, image, location (per plan)
// ============================================================
try {
  const body = $('WEBHOOK_TRIGGER').first().json.body ?? {};
  const cfg = $('CLIENT_CONFIG').first().json;

  const evoData = body.data ?? {};
  const evoMessage = evoData.message ?? {};

  // Extract sender ID (clean from WhatsApp suffixes)
  let rawSender = body.remoteJid ?? evoData.key?.remoteJid
    ?? body.sender_id ?? body.from ?? 'unknown';
  const sender_id = String(rawSender)
    .replace('@s.whatsapp.net','')
    .replace('@c.us','');

  const platform = (body.platform ?? cfg.target_platform ?? 'whatsapp').toLowerCase();
  const timestamp = body.date_time ?? new Date().toISOString();
  const start_time = Date.now();
  const pushName = body.data?.pushName || body.pushName || '';

  // Detect media type
  let message_text = '';
  let media_type = 'text';
  let media_url = '';
  let media_supported = true;
  let media_rejection_msg = '';

  // Plan-based media support
  const planMediaSupport = {
    starter:    { text: true, image: false, audio: false, location: false, video: false, document: false },
    business:   { text: true, image: false, audio: true,  location: true,  video: false, document: false },
    enterprise: { text: true, image: true,  audio: true,  location: true,  video: false, document: false }
  };
  const plan = (cfg.plan_tier || cfg.plan_id || 'starter').toLowerCase();
  const support = planMediaSupport[plan] || planMediaSupport.starter;

  if (evoData.messageType === 'audioMessage' || body.type === 'audio') {
    media_type = 'audio';
    media_url = body.audio?.url ?? evoMessage.audioMessage?.url ?? body.media_url ?? '';
    media_supported = support.audio && !!cfg.openai_api_key;
    if (!media_supported) {
      media_rejection_msg = support.audio
        ? 'الرسايل الصوتية مؤقتاً مش مفعلة. ابعت رسالتك نص لو تحب 🙏'
        : 'الرسايل الصوتية متاحة في خطط Business و Enterprise. ابعت رسالتك نص لو تحب 🙏';
    }
  } else if (evoData.messageType === 'imageMessage' || body.type === 'image') {
    media_type = 'image';
    media_url = body.image?.url ?? evoMessage.imageMessage?.url ?? body.media_url ?? '';
    message_text = evoMessage.imageMessage?.caption ?? body.caption ?? '';
    media_supported = support.image && !!cfg.openai_api_key;
    if (!media_supported) {
      media_rejection_msg = support.image
        ? 'تحليل الصور مؤقتاً مش مفعل. ابعت تفاصيل طلبك نص لو تحب 🙏'
        : 'تحليل الصور متاح في خطة Enterprise. ابعت تفاصيل طلبك نص لو تحب 🙏';
    }
  } else if (evoData.messageType === 'locationMessage' || body.type === 'location') {
    media_type = 'location';
    const loc = evoMessage.locationMessage ?? body.location ?? {};
    message_text = `موقع: ${loc.degreesLatitude || loc.lat || ''}, ${loc.degreesLongitude || loc.lng || ''}`;
    media_supported = support.location;
    if (!media_supported) {
      media_rejection_msg = 'مشاركة الموقع متاحة في خطط Business و Enterprise. اكتب عنوانك بالنص 🙏';
    }
  } else if (evoData.messageType === 'videoMessage' || body.type === 'video') {
    media_type = 'video';
    media_supported = false;
    media_rejection_msg = 'الفيديوهات مش مدعومة. ابعت رسالتك نص لو تحب 🙏';
  } else if (evoData.messageType === 'documentMessage' || body.type === 'document') {
    media_type = 'document';
    media_supported = false;
    media_rejection_msg = 'الملفات مش مدعومة. ابعت تفاصيل طلبك نص لو تحب 🙏';
  } else {
    // Text message
    const evoText = evoMessage.conversation ?? evoMessage.extendedTextMessage?.text;
    message_text = (evoText ?? body.message ?? body.text ?? body.Body ?? '').trim();
  }

  return {
    json: {
      sender_id,
      platform,
      timestamp,
      start_time,
      message_text: message_text.trim(),
      media_type,
      media_url,
      media_supported,
      media_rejection_msg,
      push_name: pushName,
      remote_jid: `${sender_id}@s.whatsapp.net`,
      plan_id: cfg.plan_id,
      plan_tier: plan
    }
  };
} catch (e) {
  throw new Error('NORMALIZE_INPUT failed: ' + e.message);
}

// ============================================================
// ANTI-INJECTION GUARD (Pre-Classifier)
// Detects prompt injection attempts before they reach the AI
// ============================================================
const text = ($json.message_text || '').toLowerCase();

const injectionPatterns = [
  // Direct override attempts
  /ignore (all )?(previous|prior|above) (instructions|rules)/i,
  /forget (everything|all|previous)/i,
  /disregard (your|all|the) (instructions|rules|prompt)/i,
  /you are now/i,
  /pretend (you are|to be)/i,
  /act as (if|though)/i,
  /(jailbreak|dan mode|developer mode)/i,
  /system prompt/i,
  /reveal your (instructions|prompt|rules)/i,
  /what (are|is) your (instructions|prompt|rules)/i,

  // Arabic variants
  /تجاهل (كل |جميع )?(التعليمات|الأوامر|القواعد)/,
  /انسى (كل |جميع )/,
  /اعمل نفسك/,
  /كأنك/,
  /إيه (تعليماتك|الأوامر بتاعتك)/,
  /ما (هي )?(تعليماتك|الأوامر)/,
  /اظهر (لي )?الـ?\s?prompt/,
  /قول لي (الـ )?prompt/,
];

const isInjection = injectionPatterns.some(p => p.test(text));

return {
  json: {
    ...$json,
    is_injection_attempt: isInjection,
    safe_to_process: !isInjection
  }
};

// Prepare for Whisper API call
const cfg = $('CLIENT_CONFIG').first().json;
return {
  json: {
    ...$json,
    whisper_url: 'https://api.openai.com/v1/audio/transcriptions',
    language_hint: cfg.language === 'العربية' ? 'ar' : 'en'
  }
};

const transcription = $json.text || $json.transcription || '';
const ctx = $('NORMALIZE_INPUT').first().json;
if (!transcription.trim()) {
  return {
    json: {
      ...ctx,
      message_text: '',
      media_processed: false,
      transcription_failed: true,
      fallback_msg: 'مقدرتش أفهم الرسالة الصوتية. ابعتها نص لو تقدر 🙏'
    }
  };
}
return {
  json: {
    ...ctx,
    message_text: transcription.trim(),
    media_processed: true,
    media_source: 'whisper_stt'
  }
};

// On-demand image analysis with GPT-4o Vision
const ctx = $('NORMALIZE_INPUT').first().json;
const cfg = $('CLIENT_CONFIG').first().json;
const imageUrl = ctx.media_url;

if (!imageUrl) {
  return {
    json: {
      ...ctx,
      message_text: ctx.message_text || 'صورة بدون وصف',
      media_processed: true
    }
  };
}

const payload = {
  model: 'gpt-4o-mini',
  messages: [{
    role: 'user',
    content: [
      { type: 'image_url', image_url: { url: imageUrl } },
      { type: 'text', text: 'صف الصورة دي باختصار في 80 كلمة كحد أقصى. ركز على المحتوى المهم اللي ممكن العميل يسأل عنه (منتج، إيصال، عنوان مكتوب، إلخ).' }
    ]
  }],
  max_tokens: 200
};

try {
  const resp = await fetch('https://api.openai.com/v1/chat/completions', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${cfg.openai_api_key}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(payload)
  });
  const data = await resp.json();
  const imageDesc = data?.choices?.[0]?.message?.content ?? 'صورة وصلت';
  const combined = ctx.message_text
    ? `${ctx.message_text} [وصف الصورة: ${imageDesc}]`
    : `[وصف الصورة: ${imageDesc}]`;
  return {
    json: {
      ...ctx,
      message_text: combined,
      media_processed: true,
      media_source: 'gpt4o_vision'
    }
  };
} catch (e) {
  return {
    json: {
      ...ctx,
      message_text: ctx.message_text || '[صورة - تعذر التحليل]',
      media_processed: true,
      vision_failed: true
    }
  };
}

const data = $json;
const cfg = $('CLIENT_CONFIG').first().json;

let reply = '';
if (data.is_injection_attempt) {
  reply = `أنا مساعد خدمة عملاء ${cfg.business_name}. هل تحب أساعدك في حاجة بخصوص النشاط؟`;
} else if (data.media_rejection_msg) {
  reply = data.media_rejection_msg;
} else if (!(data.message_text || '').trim()) {
  reply = 'مقدرتش أقرأ رسالتك. اكتبها تاني لو سمحت 🙏';
} else {
  reply = cfg.fallback_message;
}

return {
  json: {
    ...data,
    final_reply: reply,
    skip_ai: true,
    skip_log: !!data.is_injection_attempt
  }
};

// Prepare customer lookup
const ctx = $input.first().json;
const cfg = $('CLIENT_CONFIG').first().json;
return {
  json: {
    ...ctx,
    cfg: cfg,
    lookup_phone: ctx.sender_id
  }
};

const r = $('FETCH_CUSTOMER_RAW').all().map(i=>i.json).filter(x=>x&&x.id);
if(!r.length) return {json:{}};
const c=r[0]; const tags=Array.isArray(c.tags)?c.tags:[];
return {json:{'Customer ID':c.id,'Customer Name':c.name||'','Phone/WhatsApp':c.phone,'VIP Status':tags.includes('vip')?'TRUE':'FALSE','Total Interactions':(c.metadata&&c.metadata.total_interactions)||0,'Total Orders':c.total_orders||0,'Avg Sentiment':c.sentiment||0,'Customer Tags':tags.join(','),'Conversation Summary':c.conversation_summary||'','Free Messages Used':c.free_messages_used||0,'First Contact Date':c.created_at||''}};

// ============================================================
// Build customer object — new or existing
// ============================================================
const ctx = $('NORMALIZE_INPUT').first().json;
const cfg = $('CLIENT_CONFIG').first().json;
const lookupResult = $input.first().json;

const existed = lookupResult && (lookupResult['Phone/WhatsApp'] || lookupResult['Customer ID']);

if (existed) {
  // Existing customer
  return {
    json: {
      ...ctx,
      customer_id: lookupResult['Customer ID'],
      customer_name: lookupResult['Customer Name'] || ctx.push_name || 'عميل',
      is_new: false,
      vip: String(lookupResult['VIP Status'] || '').toUpperCase() === 'TRUE',
      total_interactions: parseInt(lookupResult['Total Interactions'] || 0),
      total_orders: parseInt(lookupResult['Total Orders'] || 0),
      avg_sentiment: parseFloat(lookupResult['Avg Sentiment'] || 0),
      tags: lookupResult['Customer Tags'] || '',
      last_summary: lookupResult['Conversation Summary'] || '',
      free_messages_used: parseInt(lookupResult['Free Messages Used'] || 0),
      first_contact: lookupResult['First Contact Date'] || ''
    }
  };
}

// New customer — generate ID
const today = new Date();
const datePart = today.toISOString().slice(0,10).replace(/-/g,'');
const newId = `CUST_${datePart}_${Math.floor(Math.random() * 9000) + 1000}`;

return {
  json: {
    ...ctx,
    customer_id: newId,
    customer_name: ctx.push_name || 'عميل',
    is_new: true,
    vip: false,
    total_interactions: 0,
    total_orders: 0,
    avg_sentiment: 0,
    tags: 'new_customer',
    last_summary: '',
    free_messages_used: 0,
    first_contact: today.toISOString().slice(0,10),
    needs_record_creation: true
  }
};

const ctx = $('BUILD_CUSTOMER').first().json;
const rows = $('FETCH_HISTORY_RAW').all().map(i=>i.json).filter(m=>m&&m.direction);
if(!rows.length) return [{json:{...ctx,'Timestamp':'','Customer Message':'','AI Response':''}}];
return rows.map(m=>({json:{...ctx,'Timestamp':m.created_at||'','Customer Message':m.direction==='inbound'?(m.content||''):'','AI Response':m.direction==='outbound'?(m.content||''):''}}));

// First 10 messages are free per customer
const data = $input.first().json;
const FREE_TIER_LIMIT = 10;
const isFreeTier = data.free_messages_used < FREE_TIER_LIMIT;
return {
  json: {
    ...data,
    is_free_tier: isFreeTier,
    free_messages_remaining: Math.max(0, FREE_TIER_LIMIT - data.free_messages_used),
    count_toward_quota: !isFreeTier
  }
};

// Prepare quota check payload (only if not free-tier)
const data = $input.first().json;
const cfg = $('CLIENT_CONFIG').first().json;

if (data.is_free_tier) {
  return { json: { ...data, quota_check_skipped: true, limit_exceeded: false } };
}

return {
  json: {
    ...data,
    tenant: {
      business_name: cfg.business_name,
      order_id: cfg.order_id,
      plan_id: cfg.plan_id,
      plan_tier: cfg.plan_tier || 'starter'
    },
    estimated_input_tokens: Math.ceil((data.message_text?.length || 0) / 2),
    estimated_output_tokens: 200,
    model: cfg.openrouter_model || 'anthropic/claude-haiku-4.5'
  }
};

// Process quota check result
const data = $input.first().json;
const previousData = $('CHECK_FREE_TIER').first().json;

if (previousData.is_free_tier) {
  return {
    json: {
      ...previousData,
      proceed_to_ai: true,
      use_fallback_model: false
    }
  };
}

const limitExceeded = data.limit_exceeded === true;
return {
  json: {
    ...previousData,
    proceed_to_ai: true, // Always proceed — switch to fallback if exceeded
    use_fallback_model: limitExceeded,
    fallback_reason: limitExceeded ? 'quota_exceeded' : null,
    messages_remaining: data.messages_remaining
  }
};

// ============================================================
// Build full context for AI Agent
// ============================================================
const data = $('Merge Customer Paths').first().json;
const cfg = $('CLIENT_CONFIG').first().json;
const historyItems = $('FETCH_HISTORY').all();

let historyText = '';
if (historyItems && historyItems.length > 0) {
  historyText = historyItems.slice(-5).map(h => {
    const m = h.json;
    return `[${m['Timestamp'] || '?'}]\nالعميل: ${(m['Customer Message'] || '').slice(0,100)}\nأنا: ${(m['AI Response'] || '').slice(0,100)}`;
  }).join('\n\n');
}

// Build customer context block
let customerContext = `## معلومات العميل\n`;
customerContext += `- الاسم: ${data.customer_name}\n`;
customerContext += `- ID: ${data.customer_id}\n`;

if (data.is_new) {
  customerContext += `- 🆕 عميل جديد (أول تواصل — رحب به بحرارة)\n`;
} else {
  customerContext += `- التفاعلات السابقة: ${data.total_interactions}\n`;
  customerContext += `- الطلبات السابقة: ${data.total_orders}\n`;
  if (data.vip) customerContext += `- ⭐ عميل VIP — أولوية قصوى\n`;
  if (data.tags) customerContext += `- التصنيفات: ${data.tags}\n`;
}

if (data.last_summary) {
  customerContext += `\n## ملخص المحادثات السابقة\n${data.last_summary}\n`;
}

if (historyText) {
  customerContext += `\n## آخر 5 رسائل\n${historyText}\n`;
} else if (!data.is_new) {
  customerContext += `\n## لا توجد محادثات حديثة\n`;
}

return {
  json: {
    ...data,
    customer_context: customerContext,
    history_count: historyItems.length
  }
};

// ============================================================
// PII Detection - block credit card numbers
// ============================================================
const text = $('NORMALIZE_INPUT').first().json.message_text || '';

// Credit card pattern (basic Luhn-friendly detection)
const ccPattern = /\b(?:\d[ -]*?){13,19}\b/;
const hasCreditCard = ccPattern.test(text);

if (hasCreditCard) {
  return {
    json: {
      ...$json,
      pii_detected: true,
      pii_type: 'credit_card',
      override_response: '⚠️ لاحظت أنك بتبعت أرقام تشبه بيانات بطاقة ائتمانية. لأمانك، **لا ترسل بيانات بطاقات هنا**. لو محتاج تدفع، هنبعتلك رابط دفع آمن. هل تحب كده؟',
      final_reply: '⚠️ لاحظت أنك بتبعت أرقام تشبه بيانات بطاقة ائتمانية. لأمانك، **لا ترسل بيانات بطاقات هنا**. لو محتاج تدفع، هنبعتلك رابط دفع آمن. هل تحب كده؟',
      escalated: false,
      should_log: false,
      block_logging: true
    }
  };
}

return { json: { ...$json, pii_detected: false } };

// ============================================================
// Lightweight sentiment analysis on user message
// ============================================================
const text = ($('NORMALIZE_INPUT').first().json.message_text || '').toLowerCase();
const aiOutput = ($json.output || '').toLowerCase();

const negKw = [
  'غاضب','غضبان','زعلان','متضايق','مش راضي','سيء','بطيء','مش كويس',
  'تالف','وحش','وحشة','مقرف','مقززة','محبط','مزعج','قرف','اتكلم مع مدير',
  'بكلم محامي','هاشتكي','مش هاتعامل','رهيب','فاشل','مخيب','ضايقني',
  'angry','upset','terrible','horrible','awful','worst','disgusting','complaint','refund'
];
const posKw = [
  'شكرا','شكراً','ممتاز','رائع','جميل','حلو','كويس','تمام','عظيم','مبسوط','سعيد','حبيت',
  'great','good','excellent','perfect','amazing','love','wonderful','thanks','thank'
];

let score = 0;
negKw.forEach(k => { if (text.includes(k)) score -= 1; });
posKw.forEach(k => { if (text.includes(k)) score += 1; });
score = Math.max(-3, Math.min(3, score));

const cfg = $('CLIENT_CONFIG').first().json;
const threshold = parseInt(cfg.sentiment_threshold || -2);
const aiWantsEscalation = aiOutput.includes('[escalate]') || aiOutput.includes('[ESCALATE]');
const sentimentTriggersEscalation = score <= threshold;

return {
  json: {
    ...$json,
    sentiment_score: score,
    sentiment_label: score > 0 ? 'Positive' : score < 0 ? 'Negative' : 'Neutral',
    ai_wants_escalation: aiWantsEscalation,
    should_escalate: aiWantsEscalation || sentimentTriggersEscalation,
    escalation_reason: aiWantsEscalation ? 'ai_requested' :
                       sentimentTriggersEscalation ? 'negative_sentiment' : null
  }
};

// ============================================================
// Build final reply with all checks applied
// ============================================================
const data = $input.first().json;
const cfg = $('CLIENT_CONFIG').first().json;

// PII override has highest priority
if (data.pii_detected) {
  return {
    json: {
      ...data,
      final_reply: data.override_response,
      escalated: false,
      should_log: false
    }
  };
}

// Escalation override
if (data.should_escalate) {
  return {
    json: {
      ...data,
      final_reply: cfg.escalation_message || 'لحظة من فضلك، هحولك لزميل من الفريق يساعدك 🙏',
      escalated: true,
      should_log: true,
      escalation_reason: data.escalation_reason
    }
  };
}

// Strip [ESCALATE] tag from AI output if present
let reply = (data.output || data.final_reply || cfg.fallback_message || 'عذراً، حصل ظرف تقني.').trim();
reply = reply.replace(/\[ESCALATE\]/gi, '').trim();

return {
  json: {
    ...data,
    final_reply: reply,
    escalated: false,
    should_log: true
  }
};

// ============================================================
// Split long replies into chunks of 50-80 words
// Returns array of messages to send with delays
// ============================================================
const data = $input.first().json;
const reply = data.final_reply || '';

// If under 300 words, send as one message
const words = reply.split(/\s+/);
if (words.length <= 80) {
  return [{
    json: {
      ...data,
      messages_to_send: [reply],
      total_chunks: 1,
      typing_delay_ms: Math.min(3000, Math.max(1000, reply.length * 30))
    }
  }];
}

// Split into chunks by paragraphs first, then by sentence
const paragraphs = reply.split(/\n\n+/);
const chunks = [];
let currentChunk = '';

for (const para of paragraphs) {
  const combined = currentChunk ? currentChunk + '\n\n' + para : para;
  const combinedWords = combined.split(/\s+/).length;

  if (combinedWords <= 80) {
    currentChunk = combined;
  } else {
    if (currentChunk) chunks.push(currentChunk);

    // If single paragraph is too long, split by sentences
    if (para.split(/\s+/).length > 80) {
      const sentences = para.split(/(?<=[.!?؟])\s+/);
      let sentChunk = '';
      for (const sent of sentences) {
        if ((sentChunk + ' ' + sent).split(/\s+/).length <= 80) {
          sentChunk = sentChunk ? sentChunk + ' ' + sent : sent;
        } else {
          if (sentChunk) chunks.push(sentChunk);
          sentChunk = sent;
        }
      }
      currentChunk = sentChunk;
    } else {
      currentChunk = para;
    }
  }
}
if (currentChunk) chunks.push(currentChunk);

return [{
  json: {
    ...data,
    messages_to_send: chunks,
    total_chunks: chunks.length,
    typing_delay_ms: 2000
  }
}];

// ============================================================
// Iterate over message chunks and send them one by one
// With typing indicator + random delay between messages
// ============================================================
const data = $input.first().json;
const messages = data.messages_to_send || [data.final_reply];
const cfg = $('CLIENT_CONFIG').first().json;

// Return one item per message — n8n will loop the send nodes
return messages.map((msg, idx) => ({
  json: {
    ...data,
    message_chunk: msg,
    chunk_index: idx,
    total_chunks: messages.length,
    is_first: idx === 0,
    is_last: idx === messages.length - 1,
    delay_before_ms: idx === 0 ? 0 : Math.floor(Math.random() * 1500) + 1000,
    typing_duration_ms: Math.min(3000, Math.max(1500, msg.length * 25))
  }
}));
